// HTTP-like custom protocol parser
public async Task ParseMessagesAsync(PipeReader reader, CancellationToken ct)
{
    while (true)
    {
        var result = await reader.ReadAsync(ct);
        var buffer = result.Buffer;

        while (TryParseMessage(ref buffer, out var message))
            await ProcessMessageAsync(message);

        reader.AdvanceTo(buffer.Start, buffer.End); // consumed, examined

        if (result.IsCompleted) break;
    }
    await reader.CompleteAsync();
}

